import java.awt.*;
import java.awt.geom.*;
public class TransformOrder {
    static void draw(Graphics2D g) {
        g.translate(100, 100);  // move to (100,100)
        g.rotate(Math.PI / 4); // rotate 45 degrees
        // bug: rotates around (0,0) first in local coords, then translates
        // intended: rotate around (100,100)
        g.fillRect(0, 0, 50, 10);
    }
}
